public void KPMGCommon_InitializeBatchHopperEntryDate()
{
    whsLocationProfile  whsLocationProfile = wMSLocation::find(this.wMSLocationId, this.inventDim().inventLocationId).whsLocationProfile();
    InventBatch         inventBatch = InventBatch::find(this.inventDim().inventBatchId, this.ItemId, true);
    if (this.whsWorkTable().WorkTransType == WHSWorkTransType::Invent &&
        this.WorkType == WHSWorkType::Put &&
        whsLocationProfile.KPMGCommon_EntryHopper &&
        !inventBatch.KPMGCommon_DateEntryHopper)
    {
        ttsbegin;
        inventBatch.KPMGCommon_DateEntryHopper = systemDateGet();
        inventBatch.Update();
        ttscommit;
    }
}
